const order = $("[DB] Get Order Details").item.json;
const items = $("[DB] Get Order Items").all().map(i => i.json);

const shipping = typeof order.shipping_address === 'string' 
  ? JSON.parse(order.shipping_address) 
  : (order.shipping_address || {});

// Dictionnaire étendu des pays
const countryMap = {
  'France': 'FR', 'Belgique': 'BE', 'Suisse': 'CH', 'Canada': 'CA',
  'Luxembourg': 'LU', 'Monaco': 'MC', 'Andorre': 'AD',
  'Guadeloupe': 'GP', 'Martinique': 'MQ', 'Guyane': 'GF', 'La Réunion': 'RE',
  'Mayotte': 'YT', 'Nouvelle-Calédonie': 'NC', 'Polynésie française': 'PF',
  'Saint-Barthélemy': 'BL', 'Saint-Martin': 'MF', 'Saint-Pierre-et-Miquelon': 'PM',
  'Wallis-et-Futuna': 'WF', 'Espagne': 'ES', 'Italie': 'IT', 'Royaume-Uni': 'GB',
  'Angleterre': 'GB', 'Allemagne': 'DE', 'Portugal': 'PT', 'Pays-Bas': 'NL'
};

const countryCode = countryMap[shipping.country] || 'FR';

// ON UTILISE ENFIN LES VRAIS CODES CJ ICI !
const products = items.map(item => ({
  vid: item.cj_vid || item.sku, // Priorité au Cj Vid, sinon on envoie le SKU
  quantity: item.quantity
}));

const payload = {
  orderNumber: order.order_number || '',
  shippingZip: shipping.postal_code || '',
  shippingCountryCode: countryCode,
  shippingCountry: shipping.country || 'France',
  shippingProvince: shipping.region || shipping.city || '',
  shippingCity: shipping.city || '',
  shippingAddress: [shipping.address_line1, shipping.address_line2].filter(Boolean).join(' '),
  shippingCustomerName: order.recipient_name || order.customer_name || 'Client', 
  shippingPhone: order.phone || '0000000000',
  logisticName: order.logistic_name || 'Standard',
  fromCountryCode: 'CN',
  products: products
};

return { json: payload };

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();

let billing = $input.item?.json || {};
let order = $('[DB] Get Order Details').item.json || {};

// --- NOUVEAU : GÉNÉRATION DU NUMÉRO DE FACTURE (KOKTEK PRO) ---
let lastInvoice = billing.last_invoice_number || "";
let newInvoiceNumber = "";
let currentYear = new Date().getFullYear(); // Donne 2026 (puis 2027 l'an prochain)

// Le préfixe magique qui s'adapte à l'année
let prefix = `KOKTEK-${currentYear}`; 

if (lastInvoice.startsWith(prefix + "-")) {
    // Exemple : "KOKTEK-FAC2026-0003"
    // On coupe aux tirets, ça donne ["KOKTEK", "FAC2026", "0003"]
    let parts = lastInvoice.split('-'); 
    let number = parseInt(parts[2], 10); // Le numéro est la 3ème partie (index 2)
    let nextNumber = number + 1;
    newInvoiceNumber = `${prefix}-${String(nextNumber).padStart(4, '0')}`;
} else {
    // Si on change d'année ou que c'est la toute première facture KOKTEK
    newInvoiceNumber = `${prefix}-0001`;
}
// --------------------------------------------------------------

let rawItems = $('[DB] Get Order Items').all();
let itemsList = [];

for (let i = 0; i < rawItems.length; i++) {
    let item = rawItems[i].json;
    let price = parseFloat(item.price || item.unit_price || 0);
    let qty = parseInt(item.quantity || 1, 10);
    let total = price * qty;
    let imageUrl = item.variant_image || item.main_product_image || "";

    let fullName = item.real_product_name || item.product_title || item.title || "Article";
    if (item.variant_factorized) {
        fullName += " - " + item.variant_factorized;
    }

    itemsList.push({
        name: fullName, 
        quantity: qty,
        unit_price: price.toFixed(2),
        total_price: total.toFixed(2),
        image_url: imageUrl
    });
}

let subtotal = parseFloat(order.total_products_price || 0).toFixed(2);
let shipping = parseFloat(order.shipping_price || 0).toFixed(2);
let totalOrder = parseFloat(order.total_price || 0).toFixed(2);

let finalClientName = "Client KOKTEK";
if (billing.first_name && billing.last_name) {
    finalClientName = billing.first_name + " " + billing.last_name;
} else if (billing.recipient_name) {
    finalClientName = billing.recipient_name;
}

// 💡 LE FIX EST ICI : On déduit la méthode de paiement
let finalPaymentMethod = order.payment_method;
if (!finalPaymentMethod) {
    // Si c'est vide dans la DB, on regarde la référence
    if (order.payment_reference && order.payment_reference.startsWith('pi_')) {
        finalPaymentMethod = "Carte Bancaire";
    } else {
        finalPaymentMethod = "Espèces (Paiement à la livraison)";
    }
}

let pdfData = {
    logo_url: "https://koktek.com/logo-tr.png", 
    client: {
        name: finalClientName,
        address_line1: billing.address_line1 || "",
        postal_code: billing.postal_code || "",
        city: billing.city || "",
        email: billing.customer_account_email || billing.email || order.customer_email || ""
    },
    order: {
        // ON INJECTE LE NOUVEAU NUMÉRO ICI POUR PDFMONKEY
        id: newInvoiceNumber,
        date: new Date().toLocaleDateString('fr-FR'),
        payment_method: order.payment_method || "Carte Bancaire",
        subtotal: subtotal,
        shipping: shipping,
        total: totalOrder
    },
    items: itemsList,
    // On garde l'ID de la commande en cache pour le sauvegarder dans la DB à l'étape 3
    _original_order_id: order.id 
};

return { json: pdfData };
